package main

import (
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"

	"github.com/gin-gonic/gin"
)

func uploadFileHandler(c *gin.Context) {
	// Parse the multipart form
	if err := c.Request.ParseMultipartForm(10 << 20); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Failed to parse multipart form"})
		return
	}

	// Get file from form data
	file, handler, err := c.Request.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "No file uploaded"})
		return
	}
	defer file.Close()

	// Validate file type
	allowedTypes := []string{"image/jpeg", "image/png", "application/pdf", "application/zip"}
	mimeType := handler.Header.Get("Content-Type")
	if !contains(allowedTypes, mimeType) {
		c.JSON(http.StatusUnsupportedMediaType, gin.H{"error": "Unsupported file type"})
		return
	}

	// Create a temporary file to save the uploaded file
	tempFile, err := os.CreateTemp("", "upload-*.tmp")
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create temp file"})
		return
	}
	defer os.Remove(tempFile.Name())

	// Copy the uploaded file to the temporary file
	if _, err := io.Copy(tempFile, file); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to save file"})
		return
	}

	// Move the temporary file to a public directory
	publicDir := "/path/to/public/directory"
	finalPath := filepath.Join(publicDir, handler.Filename)
	if err := os.Rename(tempFile.Name(), finalPath); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to move file"})
		return
	}

	// Return the file path
	c.JSON(http.StatusOK, gin.H{"file_path": finalPath})
}

func contains(slice []string, item string) bool {
	for _, a := range slice {
		if a == item {
			return true
		}
	}
	return false
}

func main() {
	r := gin.Default()
	r.POST("/upload", uploadFileHandler)
	r.Run(":8080")
}